public class SimpleForLoop {
  public static void main(String[] args) {
    for (int counter = 1; counter <= 5; counter++) {
      System.out.println("Təkrar: " + counter);
    }
  }
}
// Çıxış:
// Təkrar: 1
// Təkrar: 2
// Təkrar: 3
// Təkrar: 4
// Təkrar: 5

public class ForEachLoop {
  public static void main(String[] args) {
    int[] numbers = {10, 20, 30, 40, 50};
    for (int number : numbers) {
      System.out.println("Ədəd: " + number);
    }
  }
}
// Çıxış:
// Ədəd: 10
// Ədəd: 20
// Ədəd: 30
// Ədəd: 40
// Ədəd: 50

public class NestedForLoop {
  public static void main(String[] args) {
    for (int i = 1; i <= 3; i++) {
      for (int j = 1; j <= 3; j++) {
        System.out.println("i: " + i + ", j: " + j);
      }
    }
  }
}
// Çıxış:
// i: 1, j: 1
// i: 1, j: 2
// i: 1, j: 3
// i: 2, j: 1
// i: 2, j: 2
// i: 2, j: 3
// i: 3, j: 1
// i: 3, j: 2
// i: 3, j: 3

public class BreakContinueFor {
  public static void main(String[] args) {
    for (int i = 1; i <= 5; i++) {
      if (i == 3) {
        continue; // 3-ü buraxır
      }
      if (i == 5) {
        break; // Dövrü dayandırır
      }
      System.out.println("Dəyər: " + i);
    }
  }
}
// Çıxış:
// Dəyər: 1
// Dəyər: 2
// Dəyər: 4

public class PriceCalculation {
  public static void main(String[] args) {
    double[] prices = {15.5, 22.0, 10.0, 30.5};
    double total = 0.0;
    for (double price : prices) {
      total += price;
    }
    System.out.println("Ümumi qiymət: " + total);
  }
}
// Çıxış: Ümumi qiymət: 78.0

